css:
.loader {color: var(--loader-color, #16a34a);
  --loader-secondary-color: #86efac;
  --loader-bg: #ffffff;
  display: inline-flex;
  gap: 5px;
  animation: l2-0 1s infinite;
}.loader:before,.loader:after {content: "";
  width: 25px;
  aspect-ratio: 1;
  box-shadow: 0 0 0 3px inset var(--loader-bg, #ffffff);
  animation: l2-1 1s infinite;
}.loader:before {--s: -1;
}@keyframes l2-0 {0%,50% {transform: rotate(0deg)}80%,100% {transform: rotate(180deg)}}@keyframes l2-1 {0% {transform: scale(0)}50%,80% {transform: scale(calc(var(--s,1)*2.5px))}100% {transform: scale(0)}}
